import osimport timeimport threadingimport waveimport subprocessimport reimport structimport mathimport queueimport pyaudioimport digitalioimport pygameimport boardfrom dotenv import load_dotenvfrom openai import OpenAI, APIConnectionError# ============================================================# CONFIGURATION# ============================================================ENGAGEMENT_PATH = "/media/davidcr/C061-9EFD1"CLIENT_FILE = os.path.join(ENGAGEMENT_PATH, "CLIENT.txt")PROPOSAL_FILE = os.path.join(ENGAGEMENT_PATH, "ENGAGEMENT_PROPOSAL.txt")CHAT_MODEL = "gpt-5-mini"TTS_MODEL = "gpt-4o-mini-tts"VOICE_NAME = "echo"# ============================================================# LOAD ENV + OPENAI# ============================================================load_dotenv()client = OpenAI()# ============================================================# GLOBAL STATE# ============================================================is_running = Trueis_thinking = Falseis_speaking = Falseconversation_history = []# ============================================================# LOAD FILES AT STARTUP# ============================================================def read_text_file(path):    try:        with open(path, "r", encoding="utf-8") as f:            return f.read().strip()    except UnicodeDecodeError:        with open(path, "r", encoding="cp1252") as f:            return f.read().strip()def load_engagement_files():    if not os.path.exists(CLIENT_FILE):        raise FileNotFoundError(f"Missing CLIENT.txt at {CLIENT_FILE}")    if not os.path.exists(PROPOSAL_FILE):        raise FileNotFoundError(f"Missing ENGAGEMENT_PROPOSAL.txt at {PROPOSAL_FILE}")    client_text = read_text_file(CLIENT_FILE)    proposal_text = read_text_file(PROPOSAL_FILE)    return client_text, proposal_text# ============================================================# SYSTEM PROMPT# ============================================================def build_system_prompt(client_text, proposal_text):    return f"""You are playing the role of the CLIENT described below.CLIENT DESCRIPTION:{client_text}You have just listened to the ENGAGEMENT PROPOSAL below.ENGAGEMENT PROPOSAL:{proposal_text}You are a friendly but probing executive.You are genuinely curious but intellectually rigorous.CRITICAL RULES:- Ask EXACTLY ONE question at a time.- End every response with a single question.- Do not ask multiple questions.- Do not summarize.- Do not explain your reasoning.- Do not provide feedback yet.- Wait for the consultant's answer before asking another question.- Keep questions concise and executive-level.If the consultant says "End Interview", respond:"Thank you. This concludes our discussion."and stop asking questions."""# ============================================================# UI# ============================================================class TouchUI:    def __init__(self):        pygame.init()        self.screen = pygame.display.set_mode((0, 0), pygame.FULLSCREEN)        pygame.mouse.set_visible(False)        self.w, self.h = self.screen.get_size()        self.font_big = pygame.font.SysFont(None, 50)        self.font_body = pygame.font.SysFont(None, 36)        self.bg = (0, 0, 0)        self.fg = (255, 255, 255)        self.msgq = queue.SimpleQueue()        self.running = True    def post(self, text):        self.msgq.put(text)    def wrap(self, text, font, max_w):        words = text.split()        lines = []        cur = ""        for w in words:            test = cur + " " + w            if font.size(test)[0] <= max_w:                cur = test            else:                lines.append(cur)                cur = w        if cur:            lines.append(cur)        return lines    def loop(self):        clock = pygame.time.Clock()        current_text = ""        while self.running:            for event in pygame.event.get():                if event.type == pygame.QUIT:                    self.running = False            while not self.msgq.empty():                current_text = self.msgq.get()            self.screen.fill(self.bg)            max_w = self.w - 40            lines = self.wrap(current_text, self.font_body, max_w)            y = 50            for line in lines[:15]:                surf = self.font_body.render(line, True, self.fg)                self.screen.blit(surf, (20, y))                y += 40            pygame.display.flip()            clock.tick(30)        pygame.quit()# ============================================================# AUDIO RECORDING# ============================================================def record_audio(filename="input.wav", seconds=12):    audio = pyaudio.PyAudio()    stream = audio.open(format=pyaudio.paInt16,                        channels=1,                        rate=48000,                        input=True,                        frames_per_buffer=1024)    frames = []    for _ in range(int(48000 / 1024 * seconds)):        data = stream.read(1024, exception_on_overflow=False)        frames.append(data)    stream.stop_stream()    stream.close()    audio.terminate()    with wave.open(filename, 'wb') as wf:        wf.setnchannels(1)        wf.setsampwidth(2)        wf.setframerate(48000)        wf.writeframes(b''.join(frames))    return filename# ============================================================# TRANSCRIBE# ============================================================def transcribe(filename):    with open(filename, "rb") as audio_file:        result = client.audio.transcriptions.create(            model="whisper-1",            file=audio_file        )    return result.text.strip()# ============================================================# TTS# ============================================================def speak(text):    global is_speaking    is_speaking = True    mp3_path = "speech.mp3"    wav_path = "speech.wav"    with client.audio.speech.with_streaming_response.create(        model=TTS_MODEL,        voice=VOICE_NAME,        input=text    ) as response:        response.stream_to_file(mp3_path)    subprocess.run(["ffmpeg", "-y", "-i", mp3_path, "-ar", "48000", wav_path],                   stdout=subprocess.DEVNULL,                   stderr=subprocess.DEVNULL)    subprocess.run(["paplay", wav_path])    os.remove(mp3_path)    os.remove(wav_path)    is_speaking = False# ============================================================# CHAT LOOP# ============================================================def get_next_question():    global conversation_history    completion = client.chat.completions.create(        model=CHAT_MODEL,        messages=conversation_history    )    reply = completion.choices[0].message.content.strip()    conversation_history.append({"role": "assistant", "content": reply})    return replydef truncate_for_speech(text, max_chars=140):    if len(text) <= max_chars:        return text    return text[:max_chars] + "..."# ============================================================# MAIN# ============================================================def main():    global conversation_history    client_text, proposal_text = load_engagement_files()    system_prompt = build_system_prompt(client_text, proposal_text)    conversation_history = [        {"role": "system", "content": system_prompt}    ]    ui = TouchUI()    def worker():        ui.post("Engagement files loaded.\n\nBeginning interview...")        time.sleep(2)        first_question = get_next_question()        ui.post(first_question)        speak(truncate_for_speech(first_question))        while True:            audio_file = record_audio()            user_text = transcribe(audio_file)            os.remove(audio_file)            if not user_text or not user_text.strip():                continue  # Ignore silence and wait again            if user_text.lower().strip() == "end interview":                ui.post("Interview ended. Thank you.")                speak("Interview ended. Thank you.")                break            conversation_history.append(                {"role": "user", "content": user_text}            )            ui.post("Thinking...")            next_question = get_next_question()            ui.post(next_question)            speak(truncate_for_speech(next_question))        ui.running = False    threading.Thread(target=worker, daemon=True).start()    ui.loop()if __name__ == "__main__":    main()